def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None,
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by (checked on result then metadata)
        aggregation_funcs: Optional dictionary mapping statistic_name to aggregation function.
            Each aggregation function receives the list of SearchResult objects in a group
            and should return a single value.

            Example:
                {
                    "count": lambda results: len(results),
                    "max_score": lambda results: max(r.score for r in results),
                }

            If None, defaults to statistics over the `score` field:
                - count      : number of results in group
                - avg_score  : average score
                - max_score  : maximum score
                - min_score  : minimum score

    Returns:
        Dictionary mapping group_value (as string) to aggregated statistics dict.

        Example:
            {
                "tech": {
                    "count": 5,
                    "avg_score": 0.85,
                    "max_score": 0.95,
                    "min_score": 0.75,
                },
                "unknown": {
                    "count": 2,
                    "avg_score": 0.60,
                    "max_score": 0.62,
                    "min_score": 0.58,
                },
            }
    """
    # Group SearchResult objects by the requested field, falling back to metadata
    groups: Dict[str, List[SearchResult]] = defaultdict(list)

    for result in search_results:
        # Try attribute access first; if not present, fall back to .metadata
        field_value = getattr(result, group_by_field, None)
        if field_value is None:
            # Some SearchResult implementations expose metadata as .metadata (dict)
            metadata = getattr(result, "metadata", {}) or {}
            field_value = metadata.get(group_by_field)

        # Handle missing grouping field values
        if field_value is None:
            group_key = "unknown"
        else:
            group_key = str(field_value)

        groups[group_key].append(result)

    # If no custom aggregation functions are provided, use default score-based stats
    if aggregation_funcs is None:
        def default_aggregations(results: List[SearchResult]) -> Dict[str, Any]:
            # Defensive: if group is empty (shouldn't happen with grouping logic)
            if not results:
                return {
                    "count": 0,
                    "avg_score": 0.0,
                    "max_score": None,
                    "min_score": None,
                }

            scores = [getattr(r, "score", 0.0) for r in results]
            count = len(scores)
            avg_score = sum(scores) / count if count > 0 else 0.0
            return {
                "count": count,
                "avg_score": avg_score,
                "max_score": max(scores),
                "min_score": min(scores),
            }

        aggregated: Dict[str, Dict[str, Any]] = {}
        for group_key, results in groups.items():
            aggregated[group_key] = default_aggregations(results)
        return aggregated

    # Custom aggregation functions path:
    # aggregation_funcs maps statistic name -> function(List[SearchResult]) -> Any
    aggregated: Dict[str, Dict[str, Any]] = {}

    for group_key, results in groups.items():
        stats: Dict[str, Any] = {}
        for stat_name, func in aggregation_funcs.items():
            stats[stat_name] = func(results)
        aggregated[group_key] = stats

    return aggregated

