from leann.api import LeannSearcher, SearchResult


def _parse_date(value) -> datetime | None:
    """Parse various date formats into a timezone-aware datetime (UTC)."""
    if value is None:
        return None

    # If it's already a datetime
    if isinstance(value, datetime):
        if value.tzinfo is None:
            return value.replace(tzinfo=timezone.utc)
        return value.astimezone(timezone.utc)

    # Timestamps (int/float) -> seconds since epoch
    if isinstance(value, (int, float)):
        try:
            return datetime.fromtimestamp(float(value), tz=timezone.utc)
        except (OSError, ValueError):
            return None

    # Strings: try fromisoformat, then a couple of common fallbacks
    if isinstance(value, str):
        v = value.strip()
        if not v:
            return None
        try:
            # Handles 'YYYY-MM-DD', 'YYYY-MM-DDTHH:MM:SS[.ffffff][+/-HH:MM]' etc.
            dt = datetime.fromisoformat(v)
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=timezone.utc)
            else:
                dt = dt.astimezone(timezone.utc)
            return dt
        except ValueError:
            pass

        # Fallback: RFC3339-like without microseconds
        for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d"):
            try:
                dt = datetime.strptime(v, fmt)
                return dt.replace(tzinfo=timezone.utc)
            except ValueError:
                continue

    return None


def search_with_recency_boost(
    index_path: str,
    query: str,
    date_field: str,
    recency_days: int = 30,
    top_k: int = 10
) -> List[SearchResult]:
    """Search in an index and boost results based on recency of a date field.

Args:
    index_path: Path to the LEANN index file
    query: Search query string
    date_field: Metadata field name containing a date (ISO format string or timestamp)
    recency_days: Number of days to consider as "recent" (default: 30)
    top_k: Number of results to return (default: 10)

Returns:
    List of SearchResult objects with recent results ranked higher

Raises:
    FileNotFoundError: If index file is not found
    ValueError: If recency_days <= 0"""
    # Validate recency_days
    if recency_days <= 0:
        raise ValueError("recency_days must be greater than 0")

    # Ensure the index file exists
    if not Path(index_path).is_file():
        raise FileNotFoundError(f"Index file not found: {index_path}")

    # Perform the base semantic search with LEANN
    searcher = LeannSearcher(index_path=index_path)
    base_results: List[SearchResult] = searcher.search(query, top_k=top_k)

    if not base_results:
        return base_results

    now = datetime.now(timezone.utc)
    recency_window = float(recency_days)

    boosted_results = []
    for result in base_results:
        metadata = getattr(result, "metadata", {}) or {}
        raw_date = metadata.get(date_field)
        dt = _parse_date(raw_date)

        if dt is None:
            recency_factor = 1.0
        else:
            age_days = (now - dt).total_seconds() / 86400.0
            # Anything newer than recency_days gets max boost; older decays linearly to 1.0
            if age_days <= 0:
                recency_factor = 2.0
            elif age_days >= recency_window:
                recency_factor = 1.0
            else:
                # Linearly interpolate between 2.0 (new) and 1.0 (old)
                recency_factor = 1.0 + (recency_window - age_days) / recency_window

        base_score = float(getattr(result, "score", 0.0))
        boosted_score = base_score * recency_factor

        # Create a new SearchResult preserving fields but updating score
        boosted_results.append(
            SearchResult(
                id=result.id,
                text=result.text,
                metadata=metadata,
                score=boosted_score,
            )
        )

    # Sort by boosted score descending and truncate to top_k
    boosted_results.sort(key=lambda r: r.score, reverse=True)
    return boosted_results[:top_k]
