from leann.api import LeannSearcher, SearchResult


def search_with_result_expansion(
    index_path: str,
    query: str,
    expand_by_field: str,
    expansion_count: int = 1,
    top_k: int = 10,
) -> List[SearchResult]:
    """Search in an index and expand results by including additional results with matching field values.

    Args:
        index_path: Path to the LEANN index file
        query: Search query string
        expand_by_field: Metadata field name to use for expansion
        expansion_count: Number of additional results to include per unique field value (default: 1)
        top_k: Number of initial results to retrieve (default: 10)

    Returns:
        List of SearchResult objects including expanded results

    Raises:
        FileNotFoundError: If index file is not found
        ValueError: If expansion_count < 0
    """
    # Validate expansion_count
    if expansion_count < 0:
        raise ValueError("expansion_count must be non-negative")

    # Ensure index file exists (LeannSearcher may otherwise fail in a backend-specific way)
    if not Path(index_path).exists():
        raise FileNotFoundError(index_path)

    # Initialize searcher
    searcher = LeannSearcher(index_path=index_path)

    # Initial search
    initial_results: List[SearchResult] = searcher.search(query, top_k=top_k)

    # If no expansion requested or no results, just return the initial results
    if expansion_count == 0 or not initial_results:
        return initial_results

    # Collect unique field values from initial results' metadata
    field_values = []
    for res in initial_results:
        metadata = getattr(res, "metadata", {}) or {}
        if not isinstance(metadata, dict):
            continue
        if expand_by_field in metadata:
            value = metadata[expand_by_field]
            # We treat each distinct value as a category for expansion
            if value not in field_values:
                field_values.append(value)

    # If there are no field values to expand on, return initial results
    if not field_values:
        return initial_results

    # Map of result id to result to avoid duplicates
    combined_results: Dict[str, SearchResult] = {r.id: r for r in initial_results}

    # For each unique field value, search for additional results that share that value
    # We use metadata_filters to restrict by the given field.
    for value in field_values:
        if expansion_count == 0:
            continue

        try:
            extra_results = searcher.search(
                query=query,
                top_k=top_k + expansion_count,  # get enough to filter unique ones
                metadata_filters={
                    "must": {
                        expand_by_field: value,
                    }
                },
            )
        except TypeError:
            # Fallback if metadata_filters is not supported by this version;
            # in that case we cannot meaningfully expand by field, so skip.
            extra_results = []

        # Add up to `expansion_count` new results for this field value
        added_for_value = 0
        for res in extra_results:
            if res.id in combined_results:
                continue
            combined_results[res.id] = res
            added_for_value += 1
            if added_for_value >= expansion_count:
                break

    # Return results as a list; preserve original ordering of initial results
    # followed by expanded ones in arbitrary order.
    final_results: List[SearchResult] = list(initial_results)
    for res_id, res in combined_results.items():
        if res not in final_results:
            final_results.append(res)

    return final_results
